import pandas as pd
import json
from datetime import datetime

# 원본 로드
df = pd.read_excel("/home/claude/문제은행_통합_최종결과_v2.xlsx", sheet_name='통합_문제은행_마스터')

# 샘플: 각 대영역에서 2개씩만 (데모용)
sample_df = df.groupby('대영역').head(2)

print("=" * 100)
print("📦 JSON 샘플 파일 생성")
print("=" * 100)

# 1. API용 JSON (메타데이터 분리형)
api_json = {
    "metadata": {
        "version": "v1.0",
        "generated_at": datetime.now().isoformat(),
        "total_questions": len(sample_df),
        "statistics": {
            "by_area": sample_df['대영역'].value_counts().to_dict(),
            "by_difficulty": sample_df['난이도'].value_counts().to_dict()
        }
    },
    "questions": sample_df.to_dict('records')
}

with open('/home/claude/sample_api_format.json', 'w', encoding='utf-8') as f:
    json.dump(api_json, f, ensure_ascii=False, indent=2)
print("✅ 1. API용 JSON 생성: sample_api_format.json")

# 2. 웹앱용 JSON (계층적 구조)
web_json = {}
for area in sample_df['대영역'].unique():
    web_json[area] = {}
    df_area = sample_df[sample_df['대영역'] == area]
    for module in df_area['중영역'].unique():
        df_module = df_area[df_area['중영역'] == module]
        web_json[area][module] = df_module[[
            '문제ID', '문제', '정답', '난이도', '해설', '출제여부'
        ]].to_dict('records')

with open('/home/claude/sample_web_hierarchy.json', 'w', encoding='utf-8') as f:
    json.dump(web_json, f, ensure_ascii=False, indent=2)
print("✅ 2. 웹앱용 JSON 생성: sample_web_hierarchy.json")

# 3. 검색용 JSON (인덱싱)
search_json = {
    "index": {
        "by_id": {},
        "by_area": {},
        "by_difficulty": {}
    },
    "questions": {}
}

for _, row in sample_df.iterrows():
    q_id = row['문제ID']

    # 전체 문제 데이터
    search_json["questions"][q_id] = row.to_dict()

    # 인덱스 구축
    area = row['대영역']
    if area not in search_json["index"]["by_area"]:
        search_json["index"]["by_area"][area] = []
    search_json["index"]["by_area"][area].append(q_id)

    difficulty = row['난이도']
    if difficulty not in search_json["index"]["by_difficulty"]:
        search_json["index"]["by_difficulty"][difficulty] = []
    search_json["index"]["by_difficulty"][difficulty].append(q_id)

with open('/home/claude/sample_search_indexed.json', 'w', encoding='utf-8') as f:
    json.dump(search_json, f, ensure_ascii=False, indent=2)
print("✅ 3. 검색용 JSON 생성: sample_search_indexed.json")

# 4. 압축형 JSON (최소 크기)
compact_json = sample_df.to_dict('records')
with open('/home/claude/sample_compact.json', 'w', encoding='utf-8') as f:
    json.dump(compact_json, f, ensure_ascii=False)
print("✅ 4. 압축형 JSON 생성: sample_compact.json")

# 5. GraphQL 스타일 JSON
graphql_json = {
    "data": {
        "questionBank": {
            "metadata": {
                "totalCount": len(sample_df),
                "version": "v1.0"
            },
            "areas": []
        }
    }
}

for area in sample_df['대영역'].unique():
    df_area = sample_df[sample_df['대영역'] == area]
    area_obj = {
        "name": area,
        "questionCount": len(df_area),
        "modules": []
    }

    for module in df_area['중영역'].unique():
        df_module = df_area[df_area['중영역'] == module]
        module_obj = {
            "name": module,
            "questions": df_module.to_dict('records')
        }
        area_obj["modules"].append(module_obj)

    graphql_json["data"]["questionBank"]["areas"].append(area_obj)

with open('/home/claude/sample_graphql_style.json', 'w', encoding='utf-8') as f:
    json.dump(graphql_json, f, ensure_ascii=False, indent=2)
print("✅ 5. GraphQL 스타일 JSON 생성: sample_graphql_style.json")

# 파일 크기 비교
import os
files = [
    'sample_api_format.json',
    'sample_web_hierarchy.json',
    'sample_search_indexed.json',
    'sample_compact.json',
    'sample_graphql_style.json'
]

print(f"\n📊 파일 크기 비교 (샘플 {len(sample_df)}개 문제):\n")
for filename in files:
    filepath = f'/home/claude/{filename}'
    size = os.path.getsize(filepath)
    print(f"  • {filename:30s}: {size:6,} bytes ({size/1024:.1f} KB)")

print(f"\n💡 전체 672개 문제로 환산하면:")
ratio = len(df) / len(sample_df)
for filename in files:
    filepath = f'/home/claude/{filename}'
    size = os.path.getsize(filepath)
    estimated = size * ratio
    print(f"  • {filename:30s}: ~{estimated/1024:.1f} KB")

