# JSON 활용 실전 예시 코드

## 📌 목차
1. React 웹앱 예시
2. Python FastAPI 백엔드 예시
3. 검색 기능 구현
4. Excel → JSON 자동 변환 스크립트
5. 성능 최적화 팁

---

## 1. React 웹앱 예시

### 📁 구조
```
src/
├── data/
│   └── questions.json          # 계층적 JSON
├── components/
│   ├── QuestionSelector.jsx
│   ├── QuestionCard.jsx
│   └── QuestionFilter.jsx
└── App.jsx
```

### 📄 QuestionSelector.jsx
```jsx
import React, { useState, useMemo } from 'react';
import questionsData from '../data/questions.json';

function QuestionSelector() {
  const [selectedArea, setSelectedArea] = useState('DX 기초');
  const [selectedModule, setSelectedModule] = useState('');
  const [difficulty, setDifficulty] = useState('전체');
  const [examOnly, setExamOnly] = useState(false);

  // 대영역 목록
  const areas = Object.keys(questionsData);

  // 선택된 대영역의 모듈 목록
  const modules = selectedArea 
    ? Object.keys(questionsData[selectedArea]) 
    : [];

  // 필터링된 문제 목록
  const filteredQuestions = useMemo(() => {
    if (!selectedArea) return [];

    let questions = [];

    if (selectedModule) {
      // 특정 모듈의 문제만
      questions = questionsData[selectedArea][selectedModule] || [];
    } else {
      // 대영역의 모든 문제
      Object.values(questionsData[selectedArea]).forEach(moduleQuestions => {
        questions = [...questions, ...moduleQuestions];
      });
    }

    // 난이도 필터
    if (difficulty !== '전체') {
      questions = questions.filter(q => q.난이도 === difficulty);
    }

    // 출제 여부 필터
    if (examOnly) {
      questions = questions.filter(q => q.출제여부 === 'Y');
    }

    return questions;
  }, [selectedArea, selectedModule, difficulty, examOnly]);

  return (
    <div className="question-selector">
      <div className="filters">
        {/* 대영역 선택 */}
        <select 
          value={selectedArea} 
          onChange={(e) => {
            setSelectedArea(e.target.value);
            setSelectedModule('');
          }}
        >
          {areas.map(area => (
            <option key={area} value={area}>{area}</option>
          ))}
        </select>

        {/* 모듈 선택 */}
        <select 
          value={selectedModule} 
          onChange={(e) => setSelectedModule(e.target.value)}
        >
          <option value="">전체 모듈</option>
          {modules.map(module => (
            <option key={module} value={module}>{module}</option>
          ))}
        </select>

        {/* 난이도 필터 */}
        <select 
          value={difficulty} 
          onChange={(e) => setDifficulty(e.target.value)}
        >
          <option value="전체">전체 난이도</option>
          <option value="상">상</option>
          <option value="중">중</option>
          <option value="하">하</option>
        </select>

        {/* 출제 문제만 */}
        <label>
          <input 
            type="checkbox" 
            checked={examOnly}
            onChange={(e) => setExamOnly(e.target.checked)}
          />
          출제 문제만
        </label>
      </div>

      {/* 결과 통계 */}
      <div className="stats">
        총 {filteredQuestions.length}개 문제
      </div>

      {/* 문제 목록 */}
      <div className="questions">
        {filteredQuestions.map((question, idx) => (
          <QuestionCard key={question.문제ID} question={question} index={idx + 1} />
        ))}
      </div>
    </div>
  );
}

export default QuestionSelector;
```

### 📄 QuestionCard.jsx
```jsx
function QuestionCard({ question, index }) {
  const [showAnswer, setShowAnswer] = useState(false);

  const difficultyColor = {
    '상': 'red',
    '중': 'yellow',
    '하': 'green'
  };

  return (
    <div className="question-card">
      <div className="header">
        <span className="number">#{index}</span>
        <span className="id">{question.문제ID}</span>
        <span 
          className="difficulty" 
          style={{ backgroundColor: difficultyColor[question.난이도] }}
        >
          {question.난이도}
        </span>
        {question.출제여부 === 'Y' && (
          <span className="exam-badge">출제</span>
        )}
      </div>

      <div className="content">
        <p className="question-text">{question.문제}</p>

        <button onClick={() => setShowAnswer(!showAnswer)}>
          {showAnswer ? '정답 숨기기' : '정답 보기'}
        </button>

        {showAnswer && (
          <div className="answer">
            <strong>정답:</strong> {question.정답}
            {question.해설 && (
              <p className="explanation">{question.해설}</p>
            )}
          </div>
        )}
      </div>
    </div>
  );
}
```

