## 2. Python FastAPI 백엔드 예시

### 📄 main.py
```python
from fastapi import FastAPI, Query
from fastapi.middleware.cors import CORSMiddleware
from pydantic import BaseModel
from typing import Optional, List
import json

app = FastAPI(title="문제은행 API", version="1.0.0")

# CORS 설정
app.add_middleware(
    CORSMiddleware,
    allow_origins=["*"],
    allow_credentials=True,
    allow_methods=["*"],
    allow_headers=["*"],
)

# JSON 로드
with open('questions.json', 'r', encoding='utf-8') as f:
    questions_data = json.load(f)

# 평탄화 (모든 문제를 리스트로)
ALL_QUESTIONS = []
for area, modules in questions_data.items():
    for module, questions in modules.items():
        for q in questions:
            q['대영역'] = area
            q['중영역'] = module
            ALL_QUESTIONS.append(q)

# Response Model
class Question(BaseModel):
    문제ID: str
    대영역: str
    중영역: str
    문제: str
    정답: str
    난이도: str
    해설: Optional[str] = None
    출제여부: str

class QuestionListResponse(BaseModel):
    total: int
    page: int
    per_page: int
    questions: List[Question]

# API 엔드포인트
@app.get("/")
def root():
    return {
        "message": "문제은행 API",
        "version": "1.0.0",
        "total_questions": len(ALL_QUESTIONS)
    }

@app.get("/questions", response_model=QuestionListResponse)
def get_questions(
    area: Optional[str] = Query(None, description="대영역"),
    module: Optional[str] = Query(None, description="중영역"),
    difficulty: Optional[str] = Query(None, description="난이도 (상/중/하)"),
    exam_only: bool = Query(False, description="출제 문제만"),
    page: int = Query(1, ge=1),
    per_page: int = Query(20, ge=1, le=100)
):
    """문제 목록 조회"""

    # 필터링
    filtered = ALL_QUESTIONS

    if area:
        filtered = [q for q in filtered if q['대영역'] == area]

    if module:
        filtered = [q for q in filtered if q['중영역'] == module]

    if difficulty:
        filtered = [q for q in filtered if q['난이도'] == difficulty]

    if exam_only:
        filtered = [q for q in filtered if q['출제여부'] == 'Y']

    # 페이징
    start = (page - 1) * per_page
    end = start + per_page
    paginated = filtered[start:end]

    return {
        "total": len(filtered),
        "page": page,
        "per_page": per_page,
        "questions": paginated
    }

@app.get("/questions/{question_id}", response_model=Question)
def get_question(question_id: str):
    """특정 문제 조회"""
    for q in ALL_QUESTIONS:
        if q['문제ID'] == question_id:
            return q

    return {"error": "Question not found"}, 404

@app.get("/stats")
def get_stats():
    """통계 정보"""
    from collections import Counter

    return {
        "total": len(ALL_QUESTIONS),
        "by_area": dict(Counter(q['대영역'] for q in ALL_QUESTIONS)),
        "by_difficulty": dict(Counter(q['난이도'] for q in ALL_QUESTIONS)),
        "exam_count": sum(1 for q in ALL_QUESTIONS if q['출제여부'] == 'Y')
    }

@app.get("/areas")
def get_areas():
    """대영역 목록"""
    return list(questions_data.keys())

@app.get("/areas/{area}/modules")
def get_modules(area: str):
    """특정 대영역의 모듈 목록"""
    if area in questions_data:
        return list(questions_data[area].keys())
    return {"error": "Area not found"}, 404
```

