## 3. 검색 기능 구현

### 📄 search.py
```python
import json
from typing import List, Dict

class QuestionSearch:
    def __init__(self, json_file='questions.json'):
        with open(json_file, 'r', encoding='utf-8') as f:
            self.data = json.load(f)

        # 평탄화 및 인덱스 구축
        self.questions = []
        self.index = {
            'by_id': {},
            'by_area': {},
            'by_module': {},
            'by_keywords': {}
        }

        self._build_index()

    def _build_index(self):
        """인덱스 구축"""
        for area, modules in self.data.items():
            for module, questions in modules.items():
                for q in questions:
                    q['대영역'] = area
                    q['중영역'] = module

                    # 문제 추가
                    self.questions.append(q)

                    # ID 인덱스
                    self.index['by_id'][q['문제ID']] = q

                    # 영역 인덱스
                    if area not in self.index['by_area']:
                        self.index['by_area'][area] = []
                    self.index['by_area'][area].append(q['문제ID'])

                    # 모듈 인덱스
                    module_key = f"{area}:{module}"
                    if module_key not in self.index['by_module']:
                        self.index['by_module'][module_key] = []
                    self.index['by_module'][module_key].append(q['문제ID'])

                    # 키워드 인덱스 (간단한 형태소 분석)
                    keywords = self._extract_keywords(q['문제'])
                    for keyword in keywords:
                        if keyword not in self.index['by_keywords']:
                            self.index['by_keywords'][keyword] = []
                        self.index['by_keywords'][keyword].append(q['문제ID'])

    def _extract_keywords(self, text: str) -> List[str]:
        """간단한 키워드 추출 (실제로는 형태소 분석기 사용 권장)"""
        # 예: "데이터", "분석", "머신러닝" 등
        keywords = []
        important_words = [
            '데이터', '분석', '머신러닝', '인공지능', 'AI', 'DX',
            '디지털', '프로세스', '자동화', '최적화', '예측',
            '알고리즘', '모델', '시각화', '통계'
        ]
        for word in important_words:
            if word in text:
                keywords.append(word)
        return keywords

    def search(
        self,
        query: str = None,
        area: str = None,
        module: str = None,
        difficulty: str = None,
        exam_only: bool = False
    ) -> List[Dict]:
        """통합 검색"""
        results = set()

        # 텍스트 검색
        if query:
            # 키워드 기반 검색
            keywords = self._extract_keywords(query)
            for keyword in keywords:
                if keyword in self.index['by_keywords']:
                    results.update(self.index['by_keywords'][keyword])

            # 전체 텍스트 검색 (폴백)
            if not results:
                for q in self.questions:
                    if query.lower() in q['문제'].lower():
                        results.add(q['문제ID'])
        else:
            results = set(q['문제ID'] for q in self.questions)

        # 영역 필터
        if area:
            area_ids = set(self.index['by_area'].get(area, []))
            results &= area_ids

        # 모듈 필터
        if module and area:
            module_key = f"{area}:{module}"
            module_ids = set(self.index['by_module'].get(module_key, []))
            results &= module_ids

        # 결과 변환
        result_questions = [
            self.index['by_id'][qid] 
            for qid in results 
            if qid in self.index['by_id']
        ]

        # 난이도 필터
        if difficulty:
            result_questions = [
                q for q in result_questions 
                if q['난이도'] == difficulty
            ]

        # 출제 필터
        if exam_only:
            result_questions = [
                q for q in result_questions 
                if q['출제여부'] == 'Y'
            ]

        return result_questions

# 사용 예시
if __name__ == "__main__":
    searcher = QuestionSearch('questions.json')

    # 예시 1: 키워드 검색
    results = searcher.search(query="데이터 분석")
    print(f"'데이터 분석' 검색 결과: {len(results)}개")

    # 예시 2: 영역 + 난이도 필터
    results = searcher.search(area="DX 기초", difficulty="상")
    print(f"DX 기초 - 상: {len(results)}개")

    # 예시 3: 출제 문제만
    results = searcher.search(exam_only=True)
    print(f"출제 문제: {len(results)}개")
