from typing import List, Dict
import sqlite3
from datetime import datetime
import os

class ExamPDFGenerator:
    """시험지 PDF 생성기"""

    def __init__(self, db_path='question_bank.db'):
        self.db_path = db_path

    def get_exam_data(self, exam_id: str) -> Dict:
        """시험 데이터 조회"""
        conn = sqlite3.connect(self.db_path)
        conn.row_factory = sqlite3.Row
        cursor = conn.cursor()

        # 시험 정보
        cursor.execute('''
            SELECT * FROM exam_papers WHERE 시험ID = ?
        ''', (exam_id,))
        exam_info = dict(cursor.fetchone())

        # 문제 목록
        cursor.execute('''
            SELECT 
                q.*,
                eq.문제순번,
                eq.배점
            FROM questions q
            JOIN exam_questions eq ON q.문제ID = eq.문제ID
            WHERE eq.시험ID = ?
            ORDER BY eq.문제순번
        ''', (exam_id,))
        questions = [dict(row) for row in cursor.fetchall()]

        conn.close()

        return {
            'exam': exam_info,
            'questions': questions
        }

    def generate_html(self, exam_id: str, include_answers: bool = False) -> str:
