        # 통계
        total_points = sum(q['배점'] for q in questions)

        html = f'''
<!DOCTYPE html>
<html lang="ko">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>{exam['시험명']}</title>
    <style>
        @page {{
            size: A4;
            margin: 20mm;
        }}

        body {{
            font-family: 'Malgun Gothic', '맑은 고딕', sans-serif;
            font-size: 11pt;
            line-height: 1.6;
            color: #333;
            max-width: 210mm;
            margin: 0 auto;
        }}

