    def save_html(
        self, 
        exam_id: str, 
        output_dir: str = '/home/claude',
        include_answers: bool = False
    ) -> str:
        """HTML 파일 저장"""
        html = self.generate_html(exam_id, include_answers)

        suffix = '_정답지' if include_answers else '_문제지'
        filename = f"{exam_id}{suffix}.html"
        filepath = os.path.join(output_dir, filename)

        with open(filepath, 'w', encoding='utf-8') as f:
            f.write(html)

        return filepath

    def generate_pdf_via_weasyprint(
        self, 
        exam_id: str, 
        output_dir: str = '/home/claude',
        include_answers: bool = False
    ) -> str:
        """
        WeasyPrint를 사용한 PDF 생성
        (WeasyPrint 설치 필요: pip install weasyprint)
        """
        try:
            from weasyprint import HTML

            html = self.generate_html(exam_id, include_answers)

            suffix = '_정답지' if include_answers else '_문제지'
            filename = f"{exam_id}{suffix}.pdf"
            filepath = os.path.join(output_dir, filename)

            HTML(string=html).write_pdf(filepath)

            return filepath
        except ImportError:
            print("⚠️ WeasyPrint가 설치되지 않았습니다.")
            print("   HTML 파일로 저장 후 브라우저에서 PDF로 인쇄하세요.")
            return self.save_html(exam_id, output_dir, include_answers)

    def generate_complete_set(self, exam_id: str, output_dir: str = '/home/claude'):
        """문제지 + 정답지 세트 생성"""
        print(f"📄 시험지 생성 중: {exam_id}")

        # 문제지
        question_file = self.save_html(exam_id, output_dir, include_answers=False)
        print(f"  ✅ 문제지: {os.path.basename(question_file)}")

        # 정답지
        answer_file = self.save_html(exam_id, output_dir, include_answers=True)
        print(f"  ✅ 정답지: {os.path.basename(answer_file)}")

        return {
            'question_file': question_file,
            'answer_file': answer_file
        }


